"use strict";(self.webpackChunkmy_website=self.webpackChunkmy_website||[]).push([["8396"],{1715(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","href":"/docusaurus-portfolio/portfolio/intro","label":"Welcome to My Portfolio!","docId":"intro","unlisted":false},{"type":"link","href":"/docusaurus-portfolio/portfolio/meridian_introduction","label":"Product Introduction - Meridian","docId":"meridian_introduction","unlisted":false},{"type":"link","href":"/docusaurus-portfolio/portfolio/meridian_release_notes","label":"Release Notes","docId":"meridian_release_notes","unlisted":false},{"type":"category","label":"Task-Oriented Samples","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/docusaurus-portfolio/portfolio/task-oriented/sign_up","label":"Sign up","docId":"task-oriented/sign_up","unlisted":false},{"type":"link","href":"/docusaurus-portfolio/portfolio/task-oriented/sign_in","label":"Sign in","docId":"task-oriented/sign_in","unlisted":false},{"type":"link","href":"/docusaurus-portfolio/portfolio/task-oriented/map_viw_mobile","label":"View Map in Mobile","docId":"task-oriented/map_viw_mobile","unlisted":false},{"type":"link","href":"/docusaurus-portfolio/portfolio/task-oriented/config_esri_integration","label":"Configure Esri ArcGIS Integration","docId":"task-oriented/config_esri_integration","unlisted":false},{"type":"link","href":"/docusaurus-portfolio/portfolio/task-oriented/pin_photos","label":"Pin Photos in Mobile","docId":"task-oriented/pin_photos","unlisted":false}],"href":"/docusaurus-portfolio/portfolio/category/task-oriented-samples"},{"type":"category","label":"Feature Reference Samples","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/docusaurus-portfolio/portfolio/cmms/esri_integration","label":"Esri ArcGIS Integration","docId":"cmms/esri_integration","unlisted":false},{"type":"link","href":"/docusaurus-portfolio/portfolio/cmms/asset","label":"Asset Map","docId":"cmms/asset","unlisted":false},{"type":"link","href":"/docusaurus-portfolio/portfolio/cmms/data_connect","label":"Accruent Data Connect","docId":"cmms/data_connect","unlisted":false},{"type":"link","href":"/docusaurus-portfolio/portfolio/cmms/grid_view","label":"Work Order Grid View","docId":"cmms/grid_view","unlisted":false}],"href":"/docusaurus-portfolio/portfolio/category/feature-reference-samples"},{"type":"link","href":"/docusaurus-portfolio/portfolio/assets_api","label":"Assets API","docId":"assets_api","unlisted":false}]},"docs":{"assets_api":{"id":"assets_api","title":"Assets API","description":"The Assets API is a RESTful service that retrieves asset metadata and creates or updates assets in the system. It enables integration with external business systems such as Computerized Maintenance Management Systems (CMMS), Geospatial Information Systems (GIS), and Facility Management (FM) platforms.","sidebar":"tutorialSidebar"},"cmms/asset":{"id":"cmms/asset","title":"Asset Map","description":"Use the Asset map to manage assets, work orders, and maintenance workflows through an interactive geospatial interface directly in Maintenance Connection. The map helps you visualize locations, understand asset relationships, and quickly access related records.","sidebar":"tutorialSidebar"},"cmms/data_connect":{"id":"cmms/data_connect","title":"Accruent Data Connect","description":"Accruent Data Connect is an add-on product that gives you direct, secure access to cloud data in a BI-ready format. You can analyze Accruent data using your own business intelligence (BI), analytics, and enterprise tools, without manual exports or custom integrations.","sidebar":"tutorialSidebar"},"cmms/esri_integration":{"id":"cmms/esri_integration","title":"Esri ArcGIS Integration","description":"Connect Maintenance Connection assets to Esri\'s mapping platform. The integration displays your organization\u2019s Esri map in an embedded view in the Asset map, so you can interact with assets and location data directly within the application. With this integration, you can easily locate equipment, plan maintenance activities, and analyze patterns across your infrastructure.","sidebar":"tutorialSidebar"},"cmms/grid_view":{"id":"cmms/grid_view","title":"Work Order Grid View","description":"The work order grid view displays all work orders tied to the asset associated with the current work order. You can customize the columns, and filter or export the records by activating the new grid. By default, the list displays 100 items without any filters applied, and after applying filters, it displays up to 1,000 records.","sidebar":"tutorialSidebar"},"intro":{"id":"intro","title":"Welcome to My Portfolio!","description":"This portfolio showcases documentation developed during my time at Accruent and highlights my experience as a technical writer in asset management solutions.","sidebar":"tutorialSidebar"},"meridian_introduction":{"id":"meridian_introduction","title":"Meridian Introduction","description":"Meridian is an Engineering Document Management System (EDMS). It helps you to manage technical documents and drawings through their lifecicle. You can store, organize, and control access to your documents in one place. You can also manage document revisions and workflows, ensuring seemless collaboration.","sidebar":"tutorialSidebar"},"meridian_release_notes":{"id":"meridian_release_notes","title":"Release Notes","description":"We\'re delivering this automatic upgrade on February 6, 2026.","sidebar":"tutorialSidebar"},"task-oriented/config_esri_integration":{"id":"task-oriented/config_esri_integration","title":"Configure Esri ArcGIS Integration","description":"Configure the ArcGIS integration to connect your Maintenance Connection assets and work orders directly to Esri\u2019s mapping platform.","sidebar":"tutorialSidebar"},"task-oriented/map_viw_mobile":{"id":"task-oriented/map_viw_mobile","title":"View Map in Mobile","description":"Use the map in MC Kinetic to find assets and work orders, and to identify where technicians need to go.","sidebar":"tutorialSidebar"},"task-oriented/pin_photos":{"id":"task-oriented/pin_photos","title":"Pin Photos in Mobile","description":"Pin photos directly to drawing artefacts for ongoing use using the mobile app for Android and iOS. You can pin photos to a drawing as visual supporting information regardless of its workflow state or version, similar to adding a comment. For example, field technicians can pin photos to provide real-world context, making artefacts easier to understand.","sidebar":"tutorialSidebar"},"task-oriented/sign_in":{"id":"task-oriented/sign_in","title":"Sign in to Meridian Cloud","description":"If you have a user account, sign in and start using\u202FMeridian Cloud. If you don\'t have an account yet, contact your system administrator to request access and\xa0sign up.","sidebar":"tutorialSidebar"},"task-oriented/sign_up":{"id":"task-oriented/sign_up","title":"Sign up to Meridian Cloud","description":"Start using Meridian Cloud by accepting the Meridian Cloud invitation email. Once the system administrator invites you to the Meridian Cloud tenant, you receive an email with a link to accept the invitation and enter your identity information. If you don\'t receive the invitation email, check with your system administrator to confirm the email address to which the invitation was sent.","sidebar":"tutorialSidebar"}}}}')}}]);